import React from 'react';
import { Link } from 'gatsby';
import take from 'lodash/take';

let Product = (props) => {
  let handleClick = () => props.onClick(props.data);
  return (
    <button className="btn-ghost product-item" onClick={handleClick}>
      <img src={props.data.image.childImageSharp.fluid.src} alt={props.data.name}/>
      <h3>{props.data.name}</h3>
      <Link to={`/productos/serie/${props.data.family.name}`}>Series {props.data.family.name}</Link>
      <p className="product-item__usages">{take(props.data.usages, 80)}...</p>
    </button>
  )
};

export default Product;
