import React from "react"
import { Link } from "gatsby"
import NewsState, { useNews } from "../../../components/news-state"
import { makeStyles } from "@material-ui/core/styles"
import Container from "@material-ui/core/Container"
import CssBaseline from "@material-ui/core/CssBaseline"
import Grid from "@material-ui/core/Grid"
import "./news.css"

const useStyles = makeStyles(theme => ({
  container: {
    paddingTop: 100,
    paddingBottom: 80,
    flexGrow: 1,
  },
  newtitle: {
    fontSize: 30,
    fontWeight: "bold",
    color: "#000000",
    marginBottom: 8,
  },
  fecha: {
    fontSize: 17,
    color: "#000000",
    marginBottom: 10,
    lineHeight: 1.65,
  },
  contentnew: {
    fontSize: 15,
    lineHeight: 1.87,
    color: "#000000",
  },
}))

const News = () => {
  let { getPageNews, pages, currentPage } = useNews()
  let news = getPageNews() || []
  const classes = useStyles()
  return (
    <div>
      <div>
        {news.map(__new => (
          <Grid container className="divnoticia">
            <Grid item xs={12} md={8}>
              <h1 className={classes.newtitle}>{__new.title}</h1>
              <p className={classes.fecha}>{__new.created_at}</p>
              <p dangerouslySetInnerHTML={{ __html: __new.shortContent }} />
            </Grid>
            <Grid item xs={12} md={4} className="divBtnNoticia">
              <Link to={`/noticias/${__new.strapiId}`} className="btnNoticia">
                SEGUIR LEYENDO
              </Link>
            </Grid>
          </Grid>
        ))}
      </div>
      <Paginacion pages={pages} current={currentPage}></Paginacion>
    </div>
  )
}

const Paginacion = props => {
  let arr = {}
  if (props.pages > 0) {
    arr[1] = ""
    arr[props.current] = ""
    arr[props.pages] = ""
    if (props.current - 1 > 0) arr[props.current - 1] = ""
    if (props.current + 1 < props.pages) arr[props.current + 1] = ""
  }
  return (
    <div className="paginationDiv">
      {Object.keys(arr).map(key => (
        <Link to={`/noticias/page/${key}`} className="paginacion">
          {key}
        </Link>
      ))}
    </div>
  )
}

const App = props => {
  const classes = useStyles()
  return (
    <Container component="main" maxWidth="lg" className={classes.container}>
      <CssBaseline />
      <NewsState {...props}>
        <News />
      </NewsState>
    </Container>
  )
}

export default App
