import React from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import Modal from 'react-modal';

import { useLibraryState } from '../library-state';
import GridCatalogs from '../grid-catalog';
import TableCatalog from './catalog-table';
import ModalCatalog from './modal-catalog';

Modal.setAppElement('#___gatsby');
const modalStyles = {
  overlay: {
    backgroundColor: "rgba(0, 0, 0, 0.58)"
  },
  content: {
    position: "relative",
    top: "auto",
    left: "auto",
    right: "auto",
    bottom: "auto",
    maxWidth: "960px",
    margin: "32px auto",
    padding: 0,
    border: 0
  }
};

let Main = ({ path, context }) => {
  let { getData } = useLibraryState();

  let libraryData = getData();

  let [toggleModal, setToggleModal] = React.useState(false);
  let refToModal = React.useRef(null);

  let closeModal = () => {
    setToggleModal(false);
    refToModal.current = null;
  }

  let handleSelectCatalog = (data) => {
    refToModal.current = {
      data,
      flow: libraryData.flow
    };
    setToggleModal(true);
  };

  return(
    <section className="product-view__main-section">
      <h1>{libraryData.title}</h1>
      <p>{libraryData.description}</p>
      { libraryData.flow === 'catalogos' && <GridCatalogs catalogs={libraryData.items} onSelectCatalog={handleSelectCatalog} /> }
      { libraryData.flow === 'videos' && <VideosView /> }
      { libraryData.flow === 'tds-sds' && <TableCatalog families={libraryData.items} onSelectTDS={handleSelectCatalog} /> }
      <Modal
        isOpen={toggleModal}
        style={modalStyles}
        contentLabel="MODAL"
        className="catalog-modal-container"
      >
        <ModalCatalog data={refToModal.current} onClose={closeModal}/>
      </Modal>

    </section>
  );
};

let VideosView = () => {
  return <div/>
};

export default Main;

