import React from 'react';
import Carousel from 'react-slick';
import useMediaQuery from '@material-ui/core/useMediaQuery';
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome"

let ArrowButton = ({ arrow, className, ...props }) => (
  <button
    {...props}
    className={`${className} btn-arrow ${arrow}`}
  />
);

let getBackgroundStyle = (img) => {
  return {
    backgroundImage: `url(${img})`,
    backgroundSize: 'cover',
    backgroundPosition: '50% 50%',
    backgroundRepeat: 'no-repeat',
    height: '90vh'
  }
}

export default function CoverHero({
  data = [],
  render = () => null
}) {
  let settings = {
    infinite: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    dots: true,
    nextArrow: (<ArrowButton arrow={'right'}>
      <FontAwesomeIcon icon={["fas", "arrow-right"]} style={{color:"#000000"}} />
    </ArrowButton>),
    prevArrow: (<ArrowButton arrow={'left'}>
      <FontAwesomeIcon icon={["fas", "arrow-left"]} style={{color:"#000000"}} />
    </ArrowButton>),
    appendDots: (dots) => <div className="cover-hero__dots"><ul>{dots}</ul></div>,
    customPaging:() => <button className="cover-hero__dot" />
  };
  return (
    <section className="cover-hero">
      <Carousel {...settings}>
        {
          data.map((item) => (
            <div className="cover-hero__item" >
              <div style={getBackgroundStyle(item.image)} />
              <div className="cover-hero__content">
                {render(item)}
              </div>
            </div>
          ))
        }
      </Carousel>
    </section>
  )
};
