import React from "react"
import { Link } from "gatsby"
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome"

export default function ModalProduct({ product, onClose, onDownloadTDS }) {
  return (
    <div className="product-modal">
      <div className="close-modal-container">
        <button className="close-modal" onClick={onClose}>
          <FontAwesomeIcon
            icon={["fas", "times"]}
            style={{ color: "#000000" }}
          />
        </button>
      </div>
      <div className="modal-body">
        <div className="image-container">
          <img
            src={product.image.childImageSharp.fluid.src}
            alt="product-image"
          />
          <div className="actions-container">
            <span className="family">
              <Link to={`/productos/serie/${product.family.name}`}>
                Ver Serie
              </Link>
            </span>
            <span className="documents">
              <button className="btn-ghost" onClick={onDownloadTDS}>
                <FontAwesomeIcon
                  icon={["fas", "file-download"]}
                  style={{ color: "#000000" }}
                />
                &nbsp;TDS/SDS
              </button>
            </span>
          </div>
        </div>
        <div className="product-specifications">
          <h1>{product.name}</h1>
          <h4>Descripción</h4>
          <p>{product.usages}</p>
          <br />
          {product.resistencia && <p>Resistencia: {product.resistencia}</p>}
          {product.propiedades && <p>Propiedades: {product.propiedades}</p>}
          {product.viscosidad && <p>Viscosidad(mPa-s): {product.viscosidad}</p>}
          {product.torsion && <p>Torsion de ruptura(N/m): {product.torsion}</p>}
          {product.temperatura && (
            <p>Rango de temperatura de operación: {product.temperatura}</p>
          )}
          {product.apariencia && <p>Apariencia: {product.apariencia}</p>}
          <br />
          <Link className="btn btn-secondary" to="/cotiza">
            COTIZAR
          </Link>
        </div>
      </div>
    </div>
  )
}
