import React from 'react';
import { useStaticQuery, graphql } from 'gatsby';
import get from 'lodash/get';
import map from 'lodash/map';

let LibraryState = React.createContext({});

let LibrarysProvider = ({context, ...props}) => {
  let data = useStaticQuery(graphql`
  query Librarys {
    allStrapiFamilies {
      edges {
        node {
          name
          products {
            name
            tds_sds {
              publicURL
            }
          }
        }
      }
    }
    allStrapiVideoGalleries {
      edges {
        node {
          header
          description
          source
          thumb {
            childImageSharp {
              fluid {
                src
              }
            }
          }
        }
      }
    }
    allStrapiCatalogs {
      edges {
        node {
          strapiId
          name
          description
          file {
            publicURL
          }
          thumb {
            childImageSharp {
              fluid {
                src
              }
            }
          }
        }
      }
    }
  }
  `);

  let getFromData = (node, cb) => map(get(data, [node, 'edges']), ({node}) => cb ? cb(node) : node);
  let getTDS = () => getFromData('allStrapiFamilies', (family) => {
    return {
      name: family.name,
      products: family.products
    }
  });

  let getVideos = () => getFromData('allStrapiVideoGalleries', (video) => {
    return {
      title: video.header,
      description: video.description,
      source: video.source,
      coverImage: video.thumb.childImageSharp.fluid.src
    }
  });

  let getCatalogs = () => getFromData('allStrapiCatalogs', (catalog) => {
    return {
      name: catalog.name,
      description: catalog.description,
      file: catalog.file.publicURL,
      thumb: catalog.thumb.childImageSharp.fluid.src
    }
  });

  let getData = () => {
    let flow = props.path.split('/')[2] || 'catalogos';
    switch(flow) {
      case 'catalogos':
        return {
          title: 'Catálogos',
          description: `Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam`,
          flow,
          items: getCatalogs()
        };
      case 'videos':
        return {
          title: 'Videos',
          description: `Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam`,
          flow,
          items: getVideos()
        };
      case 'tds-sds':
        return {
          title: 'TDS/SDS',
          description: `Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam`,
          flow,
          items: getTDS()
        };
    };
  };

  let contextValue = {
    getTDS,
    getVideos,
    getCatalogs,
    getData
  };

  return (
    <LibraryState.Provider {...props} value={contextValue}/>
  );
};

export let useLibraryState = () => {
  let context = React.useContext(LibraryState);
  return context;
}

export default LibrarysProvider;
